const logResponse = $input.first().json;
const logId = Array.isArray(logResponse) ? logResponse[0].id : logResponse.id;
const startTime = $('Set Start Time').first().json.start_time;

// TODO: Set GA4 property IDs for each brand in n8n UI
const properties = [
  { property_id: 'GA4_PROPERTY_ID_SPA', brand_id: 1 },
  { property_id: 'GA4_PROPERTY_ID_AES', brand_id: 2 },
  { property_id: 'GA4_PROPERTY_ID_SLIM', brand_id: 3 }
];

return properties.map(p => ({ json: { ...p, log_id: logId, start_time: startTime } }));

const input = $input.first().json;
const brandId = $('Split GA4 Properties').first().json.brand_id;
const rows = input.rows || [];

const result = rows.map(row => {
  const dateRaw = row.dimensionValues[0].value; // YYYYMMDD
  const date = dateRaw.substring(0, 4) + '-' + dateRaw.substring(4, 6) + '-' + dateRaw.substring(6, 8);

  const metrics = row.metricValues;
  const bounceRate = parseFloat(metrics[5].value || 0);

  return {
    date: date,
    brand_id: brandId,
    sessions: parseInt(metrics[0].value || 0, 10),
    total_users: parseInt(metrics[1].value || 0, 10),
    new_users: parseInt(metrics[2].value || 0, 10),
    page_views: parseInt(metrics[3].value || 0, 10),
    avg_session_duration_sec: Math.round(parseFloat(metrics[4].value || 0) * 100) / 100,
    bounce_rate_pct: Math.round(bounceRate * 10000) / 100,
    conversions: parseInt(metrics[6].value || 0, 10)
  };
});

return result.map(r => ({ json: r }));

const startTime = $('Set Start Time').first().json.start_time;
const logId = $('Split GA4 Properties').first().json.log_id;
const totalRows = $input.all().length;
const durationSec = Math.round((Date.now() - startTime) / 1000);

return [{ json: {
  log_id: logId,
  status: 'success',
  rows_upserted: totalRows,
  duration_sec: durationSec
}}];
